// Minimal CUDA TOP Plugin skeleton
// Inherits from TOP_CPlusPlusBase (Derivative SDK)
#include "TOP_CPlusPlusBase.h"
#include <cuda_runtime.h>

// CUDA kernel: invert image
__global__ void invertKernel(float4* dst, const float4* src, int width, int height) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    if (x >= width || y >= height) return;
    int idx = y * width + x;
    dst[idx] = make_float4(1.0f - src[idx].x,
                           1.0f - src[idx].y,
                           1.0f - src[idx].z,
                           src[idx].w);
}

class MyCUDATOP : public TOP_CPlusPlusBase {
public:
    void execute(TOP_Output* output, const OP_Inputs* inputs, void* reserved) override {
        const OP_TOPInput* topIn = inputs->getInputTOP(0);
        if (!topIn) return;

        int w = topIn->width, h = topIn->height;

        // Map TD texture to CUDA resource
        // (requires cudaGraphicsGLRegisterImage in setupParameters)
        // Launch kernel
        dim3 block(16, 16);
        dim3 grid((w + 15) / 16, (h + 15) / 16);
        invertKernel<<<grid, block>>>(
            (float4*)d_dst, (float4*)d_src, w, h);
        cudaDeviceSynchronize();
        // Copy result back to TD output texture
    }
};

// Particle Simulation via Ping-Pong
// Input 0: Feedback TOP — current particle state (pos=RG, vel=BA in -1..1 normalized)
uniform float uDt;      // timestep
uniform vec2  uGravity; // e.g. (0.0, -0.001)
uniform float uDamping; // e.g. 0.999
uniform sampler2D sForceField; // optional force texture

void main() {
    vec2 uv = vUV.st;
    vec4 state = texture(sTD2DInputs[0], uv);

    // Decode: position and velocity are stored as 0..1, remap to -1..1
    vec2 pos = state.rg * 2.0 - 1.0; // position in NDC
    vec2 vel = state.ba * 2.0 - 1.0; // velocity

    // Apply gravity
    vel += uGravity;
    vel *= uDamping;

    // Optional: sample force field
    vec2 sampleUV = pos * 0.5 + 0.5;
    vec4 force = texture(sForceField, clamp(sampleUV, 0.0, 1.0));
    vel += (force.rg * 2.0 - 1.0) * 0.002;

    // Integrate position
    pos += vel * uDt;

    // Boundary: bounce
    if (abs(pos.x) > 1.0) { vel.x *= -0.5; pos.x = sign(pos.x); }
    if (abs(pos.y) > 1.0) { vel.y *= -0.5; pos.y = sign(pos.y); }

    // Re-encode to 0..1
    fragColor = TDOutputSwizzle(vec4(pos * 0.5 + 0.5, vel * 0.5 + 0.5));
}
